/**
 * Effective routing graph snapshot for spectral / homology proxies (Arena 5 / topo docs).
 * Edge list is undirected for Laplacian sketches; directed routing uses separate policy.
 */

export interface EdgeW {
  readonly u: number;
  readonly v: number;
  /** Positive weight (capacity proxy); default 1 */
  readonly w?: number;
}

export interface EffectiveGraphSnapshot {
  /** Number of nodes (vertices 0..n-1) */
  readonly nodeCount: number;
  readonly edges: readonly EdgeW[];
  /** Monotonic clock for ordering snapshots */
  readonly t: number;
}
